import{_ as t,c as o,o as i,ag as a}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Single Checkbox Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/single-checkbox.md","filePath":"fields/single-checkbox.md","lastUpdated":null}'),l={name:"fields/single-checkbox.md"};function n(r,e,s,d,c,h){return i(),o("div",null,e[0]||(e[0]=[a('<h1 id="single-checkbox-field" tabindex="-1">Single Checkbox Field <a class="header-anchor" href="#single-checkbox-field" aria-label="Permalink to &quot;Single Checkbox Field&quot;">​</a></h1><p>The <strong>Single Checkbox</strong> is a simple boolean toggle for straightforward Yes/No decisions. Unlike the multi-checkbox field which presents a list of choices, this field renders a single checkbox with a label.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>&quot;Add gift wrapping?&quot; (+$5.00)</li><li>&quot;Include extended warranty?&quot;</li><li>&quot;I agree to the terms and conditions&quot;</li><li>&quot;Rush my order&quot; (+$15.00)</li><li>&quot;Add insurance to my shipment?&quot;</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add a Single Checkbox field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed next to the checkbox (e.g., &quot;Add Gift Wrapping&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the checkbox (e.g., &quot;We&#39;ll wrap your item in premium packaging&quot;).</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer <strong>must</strong> tick this checkbox before adding the product to the cart. This is useful for mandatory agreements like terms and conditions.</td></tr></tbody></table><h3 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h3><p>Since the Single Checkbox does not have a choices list, pricing is configured at the <strong>field level</strong>. The price is applied when the customer checks the box.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">Choose how the field affects the product price. Available types: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, or <strong>Formula</strong>.</td></tr><tr><td style="text-align:left;"><strong>Price Amount</strong></td><td style="text-align:left;">The numeric value to add when the box is checked. For example, enter <code>5</code> for a $5.00 gift wrapping fee.</td></tr><tr><td style="text-align:left;"><strong>Formula</strong></td><td style="text-align:left;">(Only when Price Type is &quot;Formula&quot;) A math expression using placeholders like <code>[value]</code>, <code>[base_price]</code>, and <code>[quantity]</code>.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use a <strong>Percentage of Base</strong> price type to create add-ons that scale with the product price. For example, a 10% warranty on a $100 product adds $10.00, while the same warranty on a $500 product adds $50.00.</p></div><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, show a &quot;Rush Processing&quot; checkbox only when the customer selects &quot;Standard Shipping&quot; from a shipping method dropdown.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',15)]))}const p=t(l,[["render",n]]);export{u as __pageData,p as default};
